```class Solution {
public:
    int palindromePartition(string s, int k) {
        int n = s.length();
        vector<vector<char>> dp(n, vector<char>(n));

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (i == j) {
                    dp[i][j] = s[i] - 'a' + 1;
                } else if (s[i] == s[j]) {
                    dp[i][j] = 1;
                } else {
                    dp[i][j] = 2;
                }
            }
        }

        int result = 0;
        for (int i = 0; i < n; i++) {
            result = max(result, dp[i][i + k - 1]);
        }

        return result;
    }
};
